// Callback hell — evite isso
buscarUsuario(id, (usuario) => {
  buscarPedidos(usuario.id, (pedidos) => {
    buscarDetalhes(pedidos[0].id, (detalhes) => {
      // Três níveis de indentação e ainda não acabou...
    });
  });
});

// Com Promises
buscarUsuario(id)
  .then(usuario => buscarPedidos(usuario.id))
  .then(pedidos => buscarDetalhes(pedidos[0].id))
  .then(detalhes => console.log(detalhes))
  .catch(erro => console.error(erro));

// Com async/await — limpo e legível
async function carregarDetalhes(id) {
  try {
    const usuario = await buscarUsuario(id);
    const pedidos = await buscarPedidos(usuario.id);
    const detalhes = await buscarDetalhes(pedidos[0].id);
    return detalhes;
  } catch (erro) {
    console.error('Algo deu errado:', erro);
  }
}

// Server Component — sem 'use client'
async function ListaArtigos() {
  // Acesso direto ao banco de dados no servidor
  const artigos = await db.artigos.findMany();
  return (
    <ul>
      {artigos.map(a => <li key={a.id}>{a.titulo}</li>)}
    </ul>
  );
}

// Sem Generics — redundante e inseguro
function primeiroString(arr: string[]): string { return arr[0]; }
function primeiroNumber(arr: number[]): number { return arr[0]; }

// Com Generics — uma função, qualquer tipo
function primeiro<T>(arr: T[]): T | undefined {
  return arr[0];
}

const nome = primeiro(['Ana', 'Bruno']); // TypeScript sabe: string
const nota = primeiro([9.5, 8.0]);       // TypeScript sabe: number

// T deve ter uma propriedade 'id' do tipo string
function buscarPorId<T extends { id: string }>(items: T[], id: string): T | undefined {
  return items.find(item => item.id === id);
}

// Funciona com qualquer objeto que tenha 'id'
buscarPorId(usuarios, 'u-123');    // Retorna Usuario | undefined
buscarPorId(produtos, 'p-456');    // Retorna Produto | undefined

/* Flexbox brilha em layouts de eixo único */
.navbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.card {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

